#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& /*unused p*/,
                 std::vector<double>& r) {
    // Zero s in a parallel loop
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) s[j] = 0.0;

    // Main computation
    #pragma omp parallel for schedule(static) reduction(+:q[:n])
    for (int i = 0; i < n; ++i) {
        double qi = 0.0;
        const std::vector<double> &row = A[i];      // cache pointer to row
        double ri = r[i];
        for (int j = 0; j < m; ++j) {
            s[j] += ri * row[j];
            qi  += row[j] + s[j];          // s[j] was updated just above
        }
        q[i] = qi;
    }
}
