/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B) {
    const double factor = 1.0 / 3.0;            // 0.33333 as a signed double

    // Pointers to the underlying data for faster access
    double *a = A.data();
    double *b = B.data();

    // The outer time‑step loop must remain serial because every step
    // depends on the result of the previous one.
    for (int t = 0; t < tsteps; ++t) {
        // Stage 1: compute B from A
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            // Vectorised kernel – straight‑forward and cheap
            b[i] = factor * (a[i-1] + a[i] + a[i+1]);
        }

        // Stage 2: compute A from B
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = factor * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
