#include <vector>
#include <cstddef>
#include <omp.h>

/* Optimised kernel for syr2k.
   C, A, B are passed as vector of vectors with row-major storage
   (i.e. C[i][j] is stored contiguously in C[i]).
   The routine preserves the exact semantics of the original
   function while exploiting cache locality, loop tiling and
   OpenMP parallelisation. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {
    constexpr int BLOCK = 32;      // tile size (adjustable)
    const double al = alpha, bl = beta;

    // Parallelise the outer loop over the rows of C
    #pragma omp parallel for schedule(static,1)
    for (int i = 0; i < n; ++i) {
        // Scale the lower triangle of the current row
        double* const Crow = C[i].data();
        for (int j = 0; j <= i; ++j) {
            Crow[j] *= bl;
        }

        // Main computation in tiles
        for (int kk = 0; kk < m; kk += BLOCK) {
            const int kmax = (kk + BLOCK < m) ? kk + BLOCK : m;

            for (int j = 0; j <= i; ++j) {
                const double a_jk = A[j][kk];
                const double b_jk = B[j][kk];
                double sum = 0.0;

                // Unroll the inner block
                for (int k = kk; k < kmax; ++k) {
                    sum += a_jk * B[i][k] + b_jk * A[i][k];
                }

                Crow[j] += al * sum;
            }
        }
    }
}
