#include <vector>
#include <cstddef>
#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean) {
    /* 1. Compute column means ------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    /* 2. Subtract means from each column (centering) --------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    /* 3. Compute covariance matrix --------------------------------------- */
    const double inv = 1.0 / static_cast<double>(n - 1);
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* covRow = cov[i].data();
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            sum *= inv;
            covRow[j] = sum;
            cov[j][i] = sum;                // fill symmetric entry
        }
    }
}
