/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {

    // Allocate temporary storage for the inner product to avoid repeated
    // recalculation of indices.
    std::vector<double> tmp_sum(np);

    #pragma omp parallel for schedule(static) collapse(2)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            // Gather pointers to rows of A and C4 for faster access
            const std::vector<double> *a_rq = &A[r][q];
            std::vector<double> *c4_ptr = &C4[0]; // base pointer

            // Compute tmp_sum[p] = sum_s A[r][q][s] * C4[s][p]
            for (int p = 0; p < np; ++p) {
                double acc = 0.0;
                // Unroll the innermost loop for a small constant factor
                for (int s = 0; s < np; ++s) {
                    acc += (*a_rq)[s] * (*c4_ptr)[p];
                }
                tmp_sum[p] = acc;
            }

            // Write the result back into A
            std::vector<double>& a_row = A[r][q];
            for (int p = 0; p < np; ++p) {
                a_row[p] = tmp_sum[p];
            }
        }
    }
}
