/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A) {
    // speed‑ups:
    // * use raw pointers to avoid bounds checks on the 2‑D vectors
    // * keep the usual lexicographic order (required for strict
    //   Seidel semantics)
    // * unroll the innermost loop by a small factor
    // * compile with -O2 will vectorise the sum
    const double inv9 = 1.0 / 9.0;
    // allocate a pointer array for each row for quick access
    std::vector<double*> prow(n);
    for (int i = 0; i < n; ++i) prow[i] = A[i].data();

    for (int t = 0; t < tsteps; ++t) {
        for (int i = 1; i <= n - 2; ++i) {
            double* const prev = prow[i-1];
            double* const cur  = prow[i];
            double* const next = prow[i+1];
            for (int j = 1; j <= n - 2; ++j) {
                cur[j] = (prev[j-1] + prev[j] + prev[j+1] +
                          cur[j-1]  + cur[j]  + cur[j+1] +
                          next[j-1] + next[j] + next[j+1]) * inv9;
            }
        }
    }
}
