/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y) {

    // Use the same vector interface but access underlying memory directly
    // to avoid bounds checking overhead of operator[] in the inner loop.
    // Each row is already contiguous, so we can use raw pointers.
    // The outer loop is embarrassingly parallel.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double* a_row = A[i].data();     // pointer to row i of A
        const double* b_row = B[i].data();     // pointer to row i of B
        const double* x_ptr = x.data();        // pointer to x

        double tmp_i = 0.0;   // accumulator for tmp[i]
        double y_i   = 0.0;   // accumulator for y[i]

        // Inner dot-product loops
        for (int j = 0; j < n; ++j) {
            tmp_i += a_row[j] * x_ptr[j];
            y_i   += b_row[j] * x_ptr[j];
        }

        // Combine results
        y_i = alpha * tmp_i + beta * y_i;

        // Store back
        tmp[i] = tmp_i;
        y[i]   = y_i;
    }
}
