/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    // Multiply the existing matrix by beta first.
    // Parallelise the loop over rows.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* ci = C[i].data();
        for (int j = 0; j <= i; ++j) {
            ci[j] *= beta;
        }
    }

    // Perform the rank‑k update: C := alpha*A*Aᵀ + C.
    // We compute only the lower triangle (j <= i) because C is symmetric.
    // The outer two loops are parallelised to take advantage of the available
    // threads while keeping the inner loop cache‑friendly.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= i; ++j) {
            double sum = 0.0;
            double* ai = A[i].data();
            double* aj = A[j].data();
            for (int k = 0; k < m; ++k) {
                sum += ai[k] * aj[k];
            }
            C[i][j] += alpha * sum;
        }
    }
}
