#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    /* 
       Parallelise over outer i‑loop.
       All inner operations work on contiguous rows, giving
       perfect spatial locality.  The scaling of C by beta is done
       before the accumulation so that the original
       sequential effect is preserved.
    */
#pragma omp parallel for schedule(static, 1)
    for (int i = 0; i < ni; ++i)
    {
        double* const c_row = C[i].data();
        const double* const a_row = A[i].data();

        /* C[i][j] *= beta */
        for (int j = 0; j < nj; ++j) {
            c_row[j] *= beta;
        }

        /* Accumulate alpha * A[i][k] * B[k][j] */
        for (int k = 0; k < nk; ++k) {
            const double aik = alpha * a_row[k];
            const double* const b_row = B[k].data();

            /* vectorised inner loop */
            for (int j = 0; j < nj; ++j) {
                c_row[j] += aik * b_row[j];
            }
        }
    }
}
