/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {
    // Flatten the 2‑D matrix into a 1‑D contiguous array for better cache usage
    // This extra copy is done only once; for repeated calls the original
    // call‑site can provide the flattened array.
    std::vector<double> flatA(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), flatA.begin() + i * n);

    const double *restrict a = flatA.data();
    const double *restrict y1 = y_1.data();
    const double *restrict y2 = y_2.data();
    double *restrict x1ptr = x1.data();
    double *restrict x2ptr = x2.data();

    // First loop:  y1 * A   (row‑major)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double *row = a + i * n;
        double sum = x1ptr[i];
        for (int j = 0; j < n; ++j)
            sum += row[j] * y1[j];
        x1ptr[i] = sum;
    }

    // Second loop:  y2 * Aᵀ   (transpose access)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = x2ptr[i];
        for (int j = 0; j < n; ++j)
            sum += a[j * n + i] * y2[j];
        x2ptr[i] = sum;
    }
}
