/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B) {
    const double coeff = 0.2;
    // use OpenMP parallelization on the outermost loop of each sweep
    for (int t = 0; t < tsteps; ++t) {
        // Update B from A
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            // local pointers for row i and its neighbours to avoid repeated subscripting
            double *const a_cur  = A[i].data();
            double *const a_left = A[i].data() - 1;
            double *const a_right = A[i].data() + 1;
            double *const a_up   = A[i-1].data();
            double *const a_down = A[i+1].data();
            double *const b_cur  = B[i].data();
            for (int j = 1; j < n - 1; ++j) {
                b_cur[j] = coeff * (a_cur[j] + a_left[j] + a_right[j] +
                                   a_up[j]   + a_down[j]);
            }
        }

        // Update A from B
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double *const b_cur  = B[i].data();
            double *const b_left = B[i].data() - 1;
            double *const b_right = B[i].data() + 1;
            double *const b_up   = B[i-1].data();
            double *const b_down = B[i+1].data();
            double *const a_cur  = A[i].data();
            for (int j = 1; j < n - 1; ++j) {
                a_cur[j] = coeff * (b_cur[j] + b_left[j] + b_right[j] +
                                    b_up[j]   + b_down[j]);
            }
        }
    }
}
