```cpp
#include <vector>
#include <algorithm>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {
    // Allocate temporary storage once
    std::vector<double> z(n);

    double* const R = r.data();
    double* const Y = y.data();
    double* const Z = z.data();

    Y[0] = -R[0];
    double beta  = 1.0;
    double alpha = -R[0];

    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute the sum r[k-i-1] * y[i]
        double sum = 0.0;
        for (int i = 0; i < k; ++i) {
            sum += R[k - i - 1] * Y[i];
        }

        // New reflection coefficient
        alpha = -(R[k] + sum) / beta;

        // Compute the reflected y values into z
        for (int i = 0; i < k; ++i) {
            Z[i] = Y[i] + alpha * Y[k - i - 1];
        }

        // Copy back to y
        std::copy(Z, Z + k, Y);

        // Store the new coefficient
        Y[k] = alpha;
    }
}
