/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    //   Form   B := alpha * A^T * B
    // A is MxM, B is MxN

    // Parallelise the outermost loop (over i).  
    // For each i, rows i..m‑1 of B are read, but only row i is written.
    // Hence iterations are independent and safe for OpenMP.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // Pointers to the i‑th row of A and B for faster indexing.
        const double* const a_i = A.empty() ? nullptr : A[i].data();
        double* const b_i = B[i].data();

        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            // Accumulate the contributions from rows k > i.
            for (int k = i + 1; k < m; ++k) {
                // A[k][i] is the element at row k, column i of A.
                sum += A[k][i] * B[k][j];
            }
            // Add the existing value of B[i][j].
            sum += b_i[j];
            // Scale with alpha and store back.
            b_i[j] = alpha * sum;
        }
    }
}
