#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/* Optimised kernel for the Nussinov algorithm ----------------------------------------------------
 *
 *  * The algorithm is unchanged – the same dynamic‑programming recurrence is computed.
 *  * Parallelism is introduced by splitting the outer loop over `i`.  Each thread works on a
 *  * distinct row `i` of the table, so there are no data races.  The compiler will vectorise
 *  * the inner loops where possible.
 *  * A small inlined helper (`match`) is used just as in the reference code.
 *
 *  * The function signature is identical to the original – no changes are made that would
 *  * alter the behaviour expected by the harness.
 * ------------------------------------------------------------------------------------------------
 */

inline int match_val(int a, int b) noexcept {
    // returns 1 if a and b are complementary (sum to 3), else 0
    return (a + b == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int> &seq,
                     std::vector<std::vector<int>> &table) noexcept
{
    // Parallelise the outermost loop (over i) – each iteration writes only to table[i][*].
    #pragma omp parallel for schedule(static)
    for (int i = n - 1; i >= 0; --i) {
        // local pointers help the compiler to recognise contiguous memory.
        int *table_row_i = table[i].data();
        int *table_row_i1 = (i + 1 < n) ? table[i + 1].data() : nullptr;

        for (int j = i + 1; j < n; ++j) {
            int best = table_row_i[j];

            // j-1 case
            if (j - 1 >= 0) {
                best = std::max(best, table_row_i[j - 1]);
            }

            // i+1 case
            if (table_row_i1 && i + 1 < n) {
                best = std::max(best, table_row_i1[j]);
            }

            // i+1,j-1 case
            if (j - 1 >= 0 && i + 1 < n) {
                int val = table_row_i1[j - 1] + ((i < j - 1) ? match_val(seq[i], seq[j]) : 0);
                best = std::max(best, val);
            }

            // split into k
            for (int k = i + 1; k < j; ++k) {
                int val = table_row_i[k] + table[k + 1][j];
                if (val > best) best = val;
            }

            table_row_i[j] = best;
        }
    }
}
