/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
		double alpha,
		double beta,
		std::vector<std::vector<double>>& tmp,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D)
{
    // Assuming each outer vector contains a contiguous row.
    // Half‑map the pointers for faster indexing.
    double** tmp_ptr   = new double*[ni];
    double** A_ptr    = new double*[ni];
    double** B_ptr    = new double*[nk];
    double** C_ptr    = new double*[nj];
    double** D_ptr    = new double*[ni];

    for(int i=0;i<ni;i++){
        tmp_ptr[i] = tmp[i].data();
        A_ptr[i]   = A[i].data();
        D_ptr[i]   = D[i].data();
    }
    for(int k=0;k<nk;k++)
        B_ptr[k] = B[k].data();
    for(int k=0;k<nj;k++)
        C_ptr[k] = C[k].data();

    /* --- first stage: compute tmp = alpha*A*B --- */
#pragma omp parallel for schedule(static)
    for(int i=0;i<ni;i++){
        double* const tmp_row = tmp_ptr[i];
        const double* const A_row = A_ptr[i];
        for(int j=0;j<nj;j++){
            double sum = 0.0;
            const double* B_col = nullptr;
            for(int k=0;k<nk;k++){
                sum += alpha * A_row[k] * B_ptr[k][j];
            }
            tmp_row[j] = sum;
        }
    }

    /* --- second stage: D = beta*D + tmp*C --- */
#pragma omp parallel for schedule(static)
    for(int i=0;i<ni;i++){
        double* const D_row = D_ptr[i];
        const double* const tmp_row = tmp_ptr[i];
        for(int j=0;j<nl;j++){
            double sum = beta * D_row[j];
            for(int k=0;k<nj;k++){
                sum += tmp_row[k] * C_ptr[k][j];
            }
            D_row[j] = sum;
        }
    }

    delete[] tmp_ptr;
    delete[] A_ptr;
    delete[] B_ptr;
    delete[] C_ptr;
    delete[] D_ptr;
}
