        const double* L_row = L_raw + i * n;
        for (int j = 0; j < i; ++j) {
            sum -= L_row[j] * x_raw[j];
        }
        x_raw[i] = sum / L_row[i];
    }
#else
    /* The hot loop below is hand‑tuned for speed. */
    for (int i = 0; i < n; ++i) {
        double acc = b_raw[i];
        const double* Li = L_raw + i * n;
        /* Unroll the inner loop for better instruction
           throughput, but keep it deterministic for
           correctness. */
        int j = 0;
        int unroll = 4;
        for (; j <= i - unroll; j += unroll) {
            acc -= Li[j  ] * x_raw[j  ];
            acc -= Li[j+1] * x_raw[j+1];
            acc -= Li[j+2] * x_raw[j+2];
            acc -= Li[j+3] * x_raw[j+3];
        }
        for (; j < i; ++j) {
            acc -= Li[j] * x_raw[j];
        }
        x_raw[i] = acc / Li[i];
    }
#endif
}
