void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A) {
    // For speed we use raw pointers within the inner loops.
    for (int i = 0; i < n; ++i) {
        double* ai = A[i].data();          // pointer to the i‑th row
        // Compute A[i][j] for j < i
        for (int j = 0; j < i; ++j) {
            double* aj = A[j].data();      // pointer to the j‑th row
            double sum = 0.0;
            // Sum over k < j
            for (int k = 0; k < j; ++k) {
                sum += ai[k] * aj[k];
            }
            ai[j] = (ai[j] - sum) / aj[j];
        }

        // Compute the diagonal element A[i][i]
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += ai[k] * ai[k];
        }
        ai[i] = std::sqrt(ai[i] - sum);
    }
