#include <cmath>
#include <vector>
#include <numeric>
#include <omp.h>

extern "C" void kernel_correlation(int m, int n,
        std::vector<std::vector<double>>& data,
        std::vector<std::vector<double>>& corr,
        std::vector<double>& mean,
        std::vector<double>& stddev)
{
    const double eps = 0.1;
    const double inv_n = 1.0 / static_cast<double>(n);
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---------- compute means ------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum * inv_n;
    }

    /* ---------- compute stddevs ----------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum_sq = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mu;
            sum_sq += diff * diff;
        }
        double sd = std::sqrt(sum_sq * inv_n);
        stddev[j] = (sd <= eps) ? 1.0 : sd;
    }

    /* ---------- normalize data (mean‑zero, unit‑variance) ------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n * stddev[j];
        }
    }

    /* ---------- compute correlation matrix ----------------------- */
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;          // symmetry
        }
    }
    corr[m - 1][m - 1] = 1.0;
}
