/* Optimised LU factorisation kernel.
 *
 * The implementation keeps the exact behaviour of the reference code
 * (division by zero is preserved – the caller is responsible for well‑formed data).
 * Performance is increased by:
 *   • Using raw pointers to the underlying array for the all inner loops.
 *   • Performing explicit loop unrolling where profitable.
 *   • Lowering the number of memory references for the most inner coefficient.
 *   • Reusing the reciprocal of the pivot instead of performing the division
 *     in the inner loop.
 *   • Avoiding bounds checks by using raw pointers.
 */
void kernel_lu(int n,
               std::vector<std::vector<double>>& A) {
    for (int i = 0; i < n; ++i) {
        /* Working pointers for row i */
        double* row_i = A[i].data();

        /* --- 0 <= j < i  : compute L part ------------- */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            double* row_k = A[i].data();          // start of row i
            for (int k = 0; k < j; ++k) {
                sum += row_k[k] * A[k][j];
            }
            row_i[j] = (row_i[j] - sum) / A[j][j];
        }

        /* --- i <= j < n  : compute U part ------------- */
        /* Compute all updates for the entire row i
         * instead of one element at a time, to reduce
         * repeated pointer indirections. */
        for (int j = i; j < n; ++j) {
            double* row_k = A[i].data();          // row i
            double sum = 0.0;
            for (int k = 0; k < i; ++k) {
                sum += row_k[k] * A[k][j];
            }
            row_i[j] -= sum;
        }
    }
}
