/* QR Decomposition with Modified Gram Schmidt
   (http://www.inf.ethz.ch/personal/gander/) */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Work with flat pointers for contiguous storage
    double* A_ptr = &A[0][0];   // m x n matrix
    double* R_ptr = &R[0][0];   // n x n matrix
    double* Q_ptr = &Q[0][0];   // m x n matrix

    const std::size_t m_n   = static_cast<std::size_t>(m);
    const std::size_t n_n   = static_cast<std::size_t>(n);
    const std::size_t m_nz  = m_n * n_n;   // total elements in A (or Q)

    for (int k = 0; k < n; ++k) {
        // compute norm of k-th column of A
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A_ptr[i * n_n + k];
            nrm += val * val;
        }
        double Rkk = std::sqrt(nrm);
        R_ptr[k * n_n + k] = Rkk;   // store R[k][k]

        // normalize column to obtain Q[:,k]
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q_ptr[i * n_n + k] = A_ptr[i * n_n + k] / Rkk;
        }

        // compute subsequent columns
        for (int j = k + 1; j < n; ++j) {
            double dot = 0.0;
#pragma omp parallel for reduction(+:dot) schedule(static)
            for (int i = 0; i < m; ++i) {
                dot += Q_ptr[i * n_n + k] * A_ptr[i * n_n + j];
            }
            R_ptr[k * n_n + j] = dot;

            // A[:,j] -= Q[:,k] * dot
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A_ptr[i * n_n + j] -= Q_ptr[i * n_n + k] * dot;
            }
        }
    }
}
