 * used with the usual row/column indexing logic. */
static inline double* raw_ptr(std::vector<std::vector<double>>& M)
{
    return M.empty() ? nullptr : M[0].data();
}

/* Main computational kernel. The whole function will be timed,
 * including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G)
{
    /* Use raw pointers for maximal address‑space locality.
     * The loop order and computation are identical to the reference. */
    double* e = raw_ptr(E);
    double* a = raw_ptr(A);
    double* b = raw_ptr(B);
    double* f = raw_ptr(F);
    double* c = raw_ptr(C);
    double* d = raw_ptr(D);
    double* g = raw_ptr(G);

    /* 1.  E = A * B   (ni × nj) */
    #pragma omp parallel for
    for (int i = 0; i < ni; ++i) {
        double* e_row = e + i * nj;
        const double* a_row = a + i * nk;
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* b_col = b;
            for (int k = 0; k < nk; ++k) {
                sum += a_row[k] * b_col[k * nj + j];
            }
            e_row[j] = sum;
        }
    }

    /* 2.  F = C * D   (nj × nl) */
    #pragma omp parallel for
    for (int i = 0; i < nj; ++i) {
        double* f_row = f + i * nl;
        const double* c_row = c + i * nm;
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* d_col = d;
            for (int k = 0; k < nm; ++k) {
                sum += c_row[k] * d_col[k * nl + j];
            }
            f_row[j] = sum;
        }
    }

    /* 3.  G = E * F   (ni × nl) */
    #pragma omp parallel for
    for (int i = 0; i < ni; ++i) {
        double* g_row = g + i * nl;
        const double* e_row = e + i * nj;
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* f_col = f;
            for (int k = 0; k < nj; ++k) {
                sum += e_row[k] * f_col[k * nl + j];
            }
            g_row[j] = sum;
        }
    }
}
