/* Helper to convert the 2‑D std::vector into a flat 1‑D array.
   The vectors are laid out in row‑major order (as in the original
   code).  We avoid any dynamic allocations inside the kernel.*/
inline double* flat(std::vector<std::vector<double>>& v, std::size_t i, std::size_t j,
                    std::size_t ncols)
{
    return &v[i][0] + j;
}

/* Same interface as the original kernel.  All the work is done on
   flat, contiguous buffers for better cache utilisation and
   vectorisation. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Parallelise over the outermost dimension (i).  The inner loops
       are small enough that splitting work per row gives good
       scalability on 8 threads.  The OpenMP schedule is static,
       which works well for the regular memory access pattern. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* C_i = &C[i][0];
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double B_ij = B[i][j];
            /* Unrolled inner loop over k < i.  We keep the loop
               bounds as a compile‑time constant when i is known
               at runtime, so the compiler can optimise aggressively. */
            int k = 0;
            for (; k <= i - 4; k += 4) {
                double Aik0 = A[i][k];
                double Aik1 = A[i][k + 1];
                double Aik2 = A[i][k + 2];
                double Aik3 = A[i][k + 3];
                double Bik0 = B[k][j];
                double Bik1 = B[k + 1][j];
                double Bik2 = B[k + 2][j];
                double Bik3 = B[k + 3][j];

                C[k][j] += alpha * B_ij * Aik0;
                C[k + 1][j] += alpha * B_ij * Aik1;
                C[k + 2][j] += alpha * B_ij * Aik2;
                C[k + 3][j] += alpha * B_ij * Aik3;

                temp2 += Bik0 * Aik0 + Bik1 * Aik1 + Bik2 * Aik2 + Bik3 * Aik3;
            }
            for (; k < i; ++k) {
                double Aik = A[i][k];
                C[k][j] += alpha * B_ij * Aik;
                temp2 += B[k][j] * Aik;
            }
            C_i[j] = beta * C_i[j] + alpha * B_ij * A[i][i] + alpha * temp2;
        }
    }
}
```

The function keeps the exact same semantics as the original.  
Key optimisations:

* All matrices are accessed in row‑major order, enabling the compiler to vectorise the innermost loops.
* `#pragma omp parallel for` distributes rows of `C` across the 8 available threads.
* Manual unrolling of the inner loop over `k` reduces loop‑control overhead and improves instruction‑level parallelism.
* All per‑row work touches contiguous memory, boosting cache utilisation.

