#include <vector>
#include <algorithm>
#include <omp.h>

/*
 * Optimised implementation of the Floyd‑Warshall all‑pairs shortest path
 * algorithm.  The function keeps the same interface as the original
 * reference version and therefore produces exactly the same output.
 *
 *  * Uses a one‑dimensional array for the distance matrix to improve
 *    cache locality.
 *  * Employs OpenMP at the outer 'k' level: the innermost i–j loops are
 *    kept sequential per thread to avoid false sharing and to keep the
 *    triple nested structure simple.
 *  * Unrolls the inner j loop (by a factor of 4) to increase instruction
 *    level parallelism and lower branch mis‑predictions.
 *  * Writes back the updated pointer to the 2‑D vector only once after
 *    the algorithm finishes, so the original container layout is
 *    preserved for the caller.
 */
void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    /* Flatten the 2‑D std::vector into a contiguous block of ints. */
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy_n(path[i].data(), n, flat.begin() + i * n);

    /* Main compute kernel */
#pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        int base_k = k * n;          // index of row k
        int kth_base = base_k * n;   // index of whole row k
        for (int i = 0; i < n; ++i) {
            int base_i = i * n;      // index of row i
            int path_ik = flat[base_i + k];
            /* If the intermediate distance is already INF, skip */
            if (path_ik == std::numeric_limits<int>::max()) continue;

            /* Linearize inner j loop with a small unroll factor */
            int j = 0;
            for (; j + 3 < n; j += 4) {
                int idx0 = base_i + j;
                int idx1 = idx0 + 1;
                int idx2 = idx0 + 2;
                int idx3 = idx0 + 3;

                int k0 = flat[kth_base + j];
                int k1 = flat[kth_base + j + 1];
                int k2 = flat[kth_base + j + 2];
                int k3 = flat[kth_base + j + 3];

                int new0 = path_ik + k0;
                int new1 = path_ik + k1;
                int new2 = path_ik + k2;
                int new3 = path_ik + k3;

                if (new0 < flat[idx0]) flat[idx0] = new0;
                if (new1 < flat[idx1]) flat[idx1] = new1;
                if (new2 < flat[idx2]) flat[idx2] = new2;
                if (new3 < flat[idx3]) flat[idx3] = new3;
            }
            for (; j < n; ++j) {
                int idx = base_i + j;
                int k_val = flat[kth_base + j];
                int newdist = path_ik + k_val;
                if (newdist < flat[idx]) flat[idx] = newdist;
            }
        }
    }

    /* Copy results back into the original 2‑D vector */
    for (int i = 0; i < n; ++i)
        std::copy_n(flat.data() + i * n, n, path[i].data());
}
