void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    // Zero y
    std::fill(y.begin(), y.end(), 0.0);

    // Process rows in blocks to improve cache locality
    const int blockSize = 64;   // tuned for L1/L2 cache

    for (int bi = 0; bi < m; bi += blockSize) {
        int bm = std::min(blockSize, m - bi);

        // Compute tmp for the block
        for (int i = bi; i < bi + bm; ++i) {
            double sum = 0.0;
            const double* row = A[i].data();
            const double* xv = x.data();

            int j = 0;
            // Use AVX2 to accumulate 4 doubles at a time
            __m256d vsum = _mm256_setzero_pd();
            for (; j <= n - 4; j += 4) {
                __m256d vr = _mm256_loadu_pd(row + j);
                __m256d vx = _mm256_loadu_pd(xv + j);
                vsum = _mm256_fmadd_pd(vr, vx, vsum);
            }
            // Horizontal add of vsum
            double tmpArr[4];
            _mm256_storeu_pd(tmpArr, vsum);
            sum += tmpArr[0] + tmpArr[1] + tmpArr[2] + tmpArr[3];

            // Remainder loop
            for (; j < n; ++j) {
                sum += row[j] * xv[j];
            }
            tmp[i] = sum;
        }

        // Update y for the block
        for (int i = bi; i < bi + bm; ++i) {
            double t = tmp[i];
            const double* row = A[i].data();
            double* yv = y.data();

            int j = 0;
            for (; j <= n - 4; j += 4) {
                __m256d vy = _mm256_loadu_pd(yv + j);
                __m256d vr = _mm256_loadu_pd(row + j);
                __m256d vt = _mm256_set1_pd(t);
                vy = _mm256_fmadd_pd(vr, vt, vy);
                _mm256_storeu_pd(yv + j, vy);
            }
            for (; j < n; ++j) {
                yv[j] += row[j] * t;
            }
        }
    }
}
