#include <vector>
#include <omp.h>

/* Helper to flatten the 3‑D std::vector into a single contiguous array.
   The inputs are assumed to already contain n*n*n elements. */
static double* flatten(std::vector<std::vector<std::vector<double>>>& v) {
    size_t n = v.size();
    size_t total = n * n * n;
    // Allocate a temporary contiguous buffer and copy the data.
    double* buf = new double[total];
    size_t idx = 0;
    for (size_t i = 0; i < n; ++i)
        for (size_t j = 0; j < n; ++j)
            for (size_t k = 0; k < n; ++k)
                buf[idx++] = v[i][j][k];
    return buf;
}

/* Helper to copy back the contiguous buffer into the original 3‑D vector. */
static void copyBack(double* buf,
                     std::vector<std::vector<std::vector<double>>>& v) {
    size_t n = v.size();
    size_t idx = 0;
    for (size_t i = 0; i < n; ++i)
        for (size_t j = 0; j < n; ++j)
            for (size_t k = 0; k < n; ++k)
                v[i][j][k] = buf[idx++];
}

void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B) {
    const double coeff = 0.125;
    // Flatten both arrays into contiguous buffers
    double* flatA = flatten(A);
    double* flatB = flatten(B);
    size_t total = static_cast<size_t>(n) * n * n;

    /* The main time loop. Each pass swaps the roles of the buffers,
       so we only need two contiguous arrays. */
    for (int t = 0; t < tsteps; ++t) {
        /* Update B from A */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                for (int k = 1; k < n - 1; ++k) {
                    size_t idx = ((size_t)i * n + j) * n + k;
                    size_t ip = ((size_t)(i + 1) * n + j) * n + k;
                    size_t im = ((size_t)(i - 1) * n + j) * n + k;
                    size_t jp = ((size_t)i * n + (j + 1)) * n + k;
                    size_t jm = ((size_t)i * n + (j - 1)) * n + k;
                    size_t kp = ((size_t)i * n + j) * n + (k + 1);
                    size_t km = ((size_t)i * n + j) * n + (k - 1);

                    double a = flatA[idx];
                    flatB[idx] = coeff * (flatA[ip] - 2.0 * a + flatA[im])
                               + coeff * (flatA[jp] - 2.0 * a + flatA[jm])
                               + coeff * (flatA[kp] - 2.0 * a + flatA[km])
                               + a;
                }
            }
        }

        /* Update A from B (roles swapped) */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                for (int k = 1; k < n - 1; ++k) {
                    size_t idx = ((size_t)i * n + j) * n + k;
                    size_t ip = ((size_t)(i + 1) * n + j) * n + k;
                    size_t im = ((size_t)(i - 1) * n + j) * n + k;
                    size_t jp = ((size_t)i * n + (j + 1)) * n + k;
                    size_t jm = ((size_t)i * n + (j - 1)) * n + k;
                    size_t kp = ((size_t)i * n + j) * n + (k + 1);
                    size_t km = ((size_t)i * n + j) * n + (k - 1);

                    double b = flatB[idx];
                    flatA[idx] = coeff * (flatB[ip] - 2.0 * b + flatB[im])
                               + coeff * (flatB[jp] - 2.0 * b + flatB[jm])
                               + coeff * (flatB[kp] - 2.0 * b + flatB[km])
                               + b;
                }
            }
        }
    }

    // Copy the final results back into the original 3‑D vectors
    copyBack(flatA, A);
    copyBack(flatB, B);

    delete[] flatA;
    delete[] flatB;
}
