#include <cmath>
#include <vector>
#include <algorithm>
#include <omp.h>

/* ---------------------------------------------
   Optimized Deriche kernel
   --------------------------------------------- */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Parameters pre‑calculation ------------------------------------------------ */
    const double expA  = std::exp(-alpha);
    const double exp2A = expA * expA;
    const double denom = 1.0 + 2.0 * alpha * expA - exp2A;
    const double k = 1.0 - expA * (1.0 - expA) / denom;

    const float kf    = static_cast<float>(k);
    const float a1    = kf;
    const float a2    = static_cast<float>(k * expA * (alpha - 1.0));
    const float a3    = static_cast<float>(k * expA * (alpha + 1.0));
    const float a4    = static_cast<float>(-k * exp2A);
    const float a5    = a1;
    const float a6    = a2;
    const float a7    = a3;
    const float a8    = a4;
    const float b1    = static_cast<float>(std::pow(2.0, -alpha));
    const float b2    = static_cast<float>(-exp2A);
    const float c1    = 1.0f;
    const float c2    = 1.0f;

    /* ---------------------------------------------------------------  Forward scan  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        float* in  = imgIn[i].data();
        float* out = y1[i].data();

        for (int j = 0; j < h; ++j) {
            const float x = in[j];
            out[j] = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = x;
            ym2 = ym1;
            ym1 = out[j];
        }
    }

    /* ----------------------------------------------------------- Reverse scan  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f;
        float xp1 = 0.0f, xp2 = 0.0f;
        float* in  = imgIn[i].data();
        float* out = y2[i].data();

        for (int j = h - 1; j >= 0; --j) {
            const float x = in[j];
            out[j] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;  xp1 = x;
            yp2 = yp1;  yp1 = out[j];
        }
    }

    /* --------------------------- Combine horizontal results ------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);
        }
    }

    /* --------------------------- Forward scan on imgOut (vertical) ---------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float ym1 = 0.0f, ym2 = 0.0f, tm1 = 0.0f;

        for (int i = 0; i < w; ++i) {
            const float y = imgOut[i][j];
            y1[i][j] = a5 * y + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = y;
            ym2 = ym1;
            ym1 = y1[i][j];
        }
    }

    /* --------------------------- Reverse scan on imgOut (vertical) ---------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float yp1 = 0.0f, yp2 = 0.0f, tp1 = 0.0f, tp2 = 0.0f;

        for (int i = w - 1; i >= 0; --i) {
            const float y = imgOut[i][j];
            y2[i][j] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;  tp1 = y;
            yp2 = yp1;  yp1 = y2[i][j];
        }
    }

    /* --------------------------- Final combination ------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
