#include <vector>
#include <cstddef>
#include <omp.h>

/* Helper to flatten 2‑D indices into a 1‑D array */
constexpr inline std::size_t idx(std::size_t i, std::size_t j, std::size_t n) noexcept {
    return i * n + j;
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_adi(int tsteps, int n,
		std::vector<std::vector<double>>& u,
		std::vector<std::vector<double>>& v,
		std::vector<std::vector<double>>& p,
		std::vector<std::vector<double>>& q)
{
    /* Cache array size for easier indexing */
    const std::size_t nn = static_cast<std::size_t>(n);

    /* Create flattened contiguous buffers. */
    std::vector<double> uf(nn * nn), vf(nn * nn), pf(nn * nn), qf(nn * nn);
    for (std::size_t i = 0; i < nn; ++i)
        for (std::size_t j = 0; j < nn; ++j) {
            uf[idx(i,j,nn)] = u[i][j];
            vf[idx(i,j,nn)] = v[i][j];
            pf[idx(i,j,nn)] = p[i][j];
            qf[idx(i,j,nn)] = q[i][j];
        }

    /* Constants once per call */
    const double DX = 1.0 / static_cast<double>(n);
    const double DY = 1.0 / static_cast<double>(n);
    const double DT = 1.0 / static_cast<double>(tsteps);
    const double B1 = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  =  a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  =  d;

    /* Main time‑loop */
    for (int t = 1; t <= tsteps; ++t) {

        /* ---------- Forward sweep in v (column‑wise) ---------- */
        #pragma omp parallel for schedule(static)
        for (int ii = 1; ii < n - 1; ++ii) {
            const std::size_t i = static_cast<std::size_t>(ii);
            /* first row of column */
            vf[idx(0,i,nn)] = 1.0;
            pf[idx(i,0,nn)] = 0.0;
            qf[idx(i,0,nn)] = vf[idx(0,i,nn)];

            /* forward pass */
            for (int jj = 1; jj < n - 1; ++jj) {
                const std::size_t j = static_cast<std::size_t>(jj);
                double denom = a * pf[idx(i,j-1,nn)] + b;
                pf[idx(i,j,nn)] = -c / denom;
                double qp = (-d * uf[idx(j,i-1,nn)]
                            + (1.0 + 2.0 * d) * uf[idx(j,i  ,nn)]
                            - f * uf[idx(j,i+1,nn)]
                            - a * qf[idx(i,j-1,nn)])/denom;
                qf[idx(i,j,nn)] = qp;
            }

            /* last row of column */
            vf[idx(n-1,i,nn)] = 1.0;

            /* backward pass */
            for (int jj = n - 2; jj >= 1; --jj) {
                const std::size_t j = static_cast<std::size_t>(jj);
                vf[idx(j,i,nn)] = pf[idx(i,j,nn)] * vf[idx(j+1,i,nn)] + qf[idx(i,j,nn)];
            }
        }

        /* ---------- Forward sweep in u (row‑wise) ---------- */
        #pragma omp parallel for schedule(static)
        for (int ii = 1; ii < n - 1; ++ii) {
            const std::size_t i = static_cast<std::size_t>(ii);
            /* first column of row */
            uf[idx(i,0,nn)] = 1.0;
            pf[idx(i,0,nn)] = 0.0;
            qf[idx(i,0,nn)] = uf[idx(i,0,nn)];

            /* forward pass */
            for (int jj = 1; jj < n - 1; ++jj) {
                const std::size_t j = static_cast<std::size_t>(jj);
                double denom = d * pf[idx(i,j-1,nn)] + e;
                pf[idx(i,j,nn)] = -f / denom;
                double qp = (-a * vf[idx(i-1,j,nn)]
                            + (1.0 + 2.0 * a) * vf[idx(i  ,j,nn)]
                            - c * vf[idx(i+1,j,nn)]
                            - d * qf[idx(i,j-1,nn)])/denom;
                qf[idx(i,j,nn)] = qp;
            }

            /* last column of row */
            uf[idx(i,n-1,nn)] = 1.0;

            /* backward pass */
            for (int jj = n - 2; jj >= 1; --jj) {
                const std::size_t j = static_cast<std::size_t>(jj);
                uf[idx(i,j,nn)] = pf[idx(i,j,nn)] * uf[idx(i,j+1,nn)] + qf[idx(i,j,nn)];
            }
        }
    }

    /* Copy results back into the original 2‑D vectors */
    for (std::size_t i = 0; i < nn; ++i)
        for (std::size_t j = 0; j < nn; ++j) {
            u[i][j] = uf[idx(i,j,nn)];
            v[i][j] = vf[idx(i,j,nn)];
            p[i][j] = pf[idx(i,j,nn)];
            q[i][j] = qf[idx(i,j,nn)];
        }
}
